import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Edge cases: simplest ---
  it("empty item list quote → premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Single main item base premiums + processing fee ---
  it("quote single sword (steel, ench 3, not cursed), 0 yrs, 1st contract → 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("quote single amulet base premium 60 G → 60 + 6 + 5 = 71 G (newcomer, first contract)");
  it.todo("quote single staff base premium 80 G → 80 + 8 + 5 = 93 G (newcomer, first contract)");
  it.todo("quote single potion base premium 40 G → 40 + 4 + 5 = 49 G (newcomer, first contract)");

  // --- Components: rune / moonstone single & multiple, blocks ---
  it.todo("quote 1 rune → 25 base + 2.5 first → ceil → 28 + 5 fee = 33 G");
  it.todo("quote 2 runes → 50 G base premium (per spec example)");
  it.todo("quote 3 runes → 60 G base premium (block of 3 alike applies)");
  it.todo("quote 4 runes → 100 G base premium (no block; block requires exactly 3)");
  it.todo("quote 7 runes → 175 G base premium (7 × 25, no block)");

  // --- Alike-component clarification (❓) ---
  it.todo("quote 2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("quote 3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // --- Modifier scope on multi-item policies (❓) ---
  it.todo("policy with cursed sword + plain amulet → 210 G before further modifiers and fee (curse surcharge on sword only)");

  // --- Modifier thresholds ---
  it.todo("loyalty: exactly 2 years with MHPCO → loyalty discount applies");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with enchantment 5 and cursed → both surcharges apply");
  it.todo("sword with enchantment 4 not cursed → no high-enchantment, no curse surcharge");
  it.todo("sword with enchantment 4 and cursed → no high-enchantment surcharge; curse applies");

  // --- Rounding in MHPCO's favor ---
  it.todo("premium calculation yielding 197.5 G → 198 G (rounded up)");
  it.todo("payout calculation yielding 350.5 G → 350 G (rounded down)");
  it.todo("intermediate amounts kept as fractions; only final rounded");

  // --- Claim processing: standard reimbursement ---
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full − 100 deductible)");
  it.todo("rune damage 200 G → payout 100 G (full − 100 deductible; no special clauses for components)");

  // --- Claim: enchantment threshold & dragon material interactions ---
  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-ench wins, 50% then deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon full reimbursement − deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (high-ench: 50% − deductible)");

  // --- Deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (100 deductible per item)");

  // --- Multiple items of the same type ---
  it.todo("policy of two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("policy of two swords, both damaged → each entry has its own deductible");
  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero (claim rejected)");

  // --- Cap exhaustion ---
  it.todo("policy with sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (premium with modifiers 165) → cap 2000 G (based on unmodified insurance value)");
  it.todo("policy with sword + 3 runes (block) → insurance sum 1750 G (block discount does not affect insurance sum)");
  it.todo("sword cap 2000 G; two successive claims of 1500 each → 1st payout 1400, cap left 600; 2nd payout 600, cap 0");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (steel ench 3): 0 yrs, 1st contract → 165 G (100 + 50 curse + 10 first + 5 fee)");
  it.todo("long-standing customer 3 yrs, 2nd contract, cursed sword steel ench 7 → 160 G (100+50+30−20+10−15+5)");

  // --- Edge cases: error handling ---
  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero, error to stderr");
  it.todo("claim references item not in policy (e.g. amulet damaged when only sword insured) → CLI exits non-zero");
  it.todo("claim damages includes unknown item type → CLI exits non-zero");
  it.todo("claim has damage entry with negative amount → CLI exits non-zero");

  // --- CLI/scenario shape ---
  it.todo("scenario with quote + claim returns results array of same length and order");
  it.todo("claim references policy by zero-based step index");
});

