export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type QuoteStep = { op: "quote"; items: Item[] };
export type Step = QuoteStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type ScenarioResult = { results: QuoteResult[] };

const PROCESSING_FEE = 5;
const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const itemPremium = (item: Item): number => {
  const basePremium = BASE_PREMIUMS[item.type];
  return basePremium + basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
};

const quoteStep = (step: QuoteStep): QuoteResult => {
  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  return { results: scenario.steps.map(quoteStep) };
};

