export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type QuoteStep = { op: "quote"; items: Item[] };
export type Step = QuoteStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type ScenarioResult = { results: QuoteResult[] };

const PROCESSING_FEE = 5;
const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const countByType = (items: Item[]): Record<string, number> => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return counts;
};

const componentGroupPremium = (type: string, count: number): number =>
  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];

const itemsBasePremium = (items: Item[]): number => {
  const mainItems = items.filter((item) => !isComponent(item));
  const components = items.filter(isComponent);
  const mainTotal = mainItems.reduce(
    (sum, item) => sum + BASE_PREMIUMS[item.type],
    0,
  );
  const componentTotal = Object.entries(countByType(components)).reduce(
    (sum, [type, count]) => sum + componentGroupPremium(type, count),
    0,
  );
  return mainTotal + componentTotal;
};

const quoteStep = (step: QuoteStep): QuoteResult => {
  const base = itemsBasePremium(step.items);
  const withFirstContract = base + base * FIRST_CONTRACT_SURCHARGE_RATE;
  return { premium: Math.ceil(withFirstContract + PROCESSING_FEE) };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  return { results: scenario.steps.map(quoteStep) };
};

