type PolicyState = { items: Item[]; insuranceSum: number; remainingCap: number };

const insuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);

const claimStep = (step: ClaimStep, policies: Map<number, PolicyState>): ClaimResult => {
  const policy = policies.get(step.policy)!;
  const totalPayout = step.incident.damages.reduce(
    (sum, dmg) => sum + (dmg.amount - DEDUCTIBLE),
    0,
  );
  policy.remainingCap -= totalPayout;
  return { payout: totalPayout, remainingCap: policy.remainingCap };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const policies = new Map<number, PolicyState>();
  const results: StepResult[] = [];
  scenario.steps.forEach((step, idx) => {
    if (step.op === "quote") {
      results.push(quoteStep(step, scenario.customer.yearsWithMHPCO));
      const sum = insuranceSum(step.items);
      policies.set(idx, { items: step.items, insuranceSum: sum, remainingCap: sum * CAP_MULTIPLIER });
    } else {
      results.push(claimStep(step, policies));
    }
  });
  return { results };
};

