134	
135	const damagePayout = (damage: Damage, items: Item[]): number => {
136	  const item = items.find((i) => i.type === damage.itemType);
137	  return reimbursableAmount(item, damage.amount) - DEDUCTIBLE;
138	};
139	
140	const assertNonNegativeAmounts = (damages: Damage[]): void => {
141	  for (const dmg of damages) {
142	    if (dmg.amount < 0) throw new Error(`claim rejected: negative damage amount ${dmg.amount}`);
143	  }
144	};
145	
146	const validateDamageCounts = (damages: Damage[], items: Item[]): void => {
147	  const itemCounts = countItemsByType(items);
148	  const damageCounts = countBy(damages, (dmg) => dmg.itemType);
149	  for (const [type, count] of Object.entries(damageCounts)) {
150	    if (count > (itemCounts[type] ?? 0)) throw new Error(`claim rejected: more damages of type ${type} than insured`);
151	  }
152	};
153	
154	const totalDamagePayout = (damages: Damage[], items: Item[]): number =>
155	  damages.reduce((sum, dmg) => sum + damagePayout(dmg, items), 0);
156	
157	// Payouts are rounded down so the rounding favors MHPCO, never the customer.
158	const roundInMHPCOsFavor = (amount: number): number => Math.floor(amount);
159	
160	const claimStep = (step: ClaimStep, policies: Map<number, PolicyState>): ClaimResult => {
161	  const policy = policies.get(step.policy)!;
162	  assertNonNegativeAmounts(step.incident.damages);
163	  validateDamageCounts(step.incident.damages, policy.items);
164	  const uncappedPayout = totalDamagePayout(step.incident.damages, policy.items);
165	  const payout = roundInMHPCOsFavor(Math.min(uncappedPayout, policy.remainingCap));
166	  policy.remainingCap -= payout;
167	  return { payout, remainingCap: policy.remainingCap };
168	};
169	
170	const newPolicyState = (items: Item[]): PolicyState => {
171	  const sum = insuranceSum(items);
172	  return { items, insuranceSum: sum, remainingCap: sum * CAP_MULTIPLIER };
173	};
174	
175	export const runScenario = (scenario: Scenario): ScenarioResult => {
176	  const policies = new Map<number, PolicyState>();
177	  const results: StepResult[] = [];
178	  let hasPriorQuote = false;
179	  scenario.steps.forEach((step, idx) => {
180	    if (step.op === "quote") {
181	      results.push(quoteStep(step, scenario.customer.yearsWithMHPCO, hasPriorQuote));
182	      policies.set(idx, newPolicyState(step.items));
183	      hasPriorQuote = true;
184	    } else {
185	      results.push(claimStep(step, policies));
186	    }
187	  });
188	  return { results };
189	};

